import { useEffect, useState } from "react";
import { fetchPubMedResearch } from ".//pubmedService";
import "./ResearchTicker.css";

export default function ResearchTicker() {
  const [research, setResearch] = useState([]);

  useEffect(() => {
    fetchPubMedResearch()
      .then(setResearch)
      .catch((err) => console.error("PubMed error:", err));
  }, []);

  if (!research.length) {
    return (
      <div className="research-ticker">
        <span>Loading research preview...</span>
      </div>
    );
  }

  return (
    <div className="research-ticker">
      <span>Research preview:</span>
      {research.map((item, index) => (
        <a
          key={index}
          href={item.link}
          target="_blank"
          rel="noreferrer"
        >
          • {item.title}
        </a>
      ))}
    </div>
  );
}
